import{stringifyEntities}from"stringify-entities";const htmlCommentRegex=/^>|^->|<!--|-->|--!>|<!-$/g,bogusCommentEntitySubset=[">"],commentEntitySubset=["<",">"];export function comment(t,e,n,s){return s.settings.bogusComments?"<?"+stringifyEntities(t.value,Object.assign({},s.settings.characterReferences,{subset:bogusCommentEntitySubset}))+">":"\x3c!--"+t.value.replace(htmlCommentRegex,function(t){return stringifyEntities(t,Object.assign({},s.settings.characterReferences,{subset:commentEntitySubset}))})+"--\x3e"}